<template>
    <div>
        <section class="main-content">
            <loader :is-visible="isLoading"></loader>
            <div id="divMainLeadData">
                <div class="row" v-if="callFrom != 'Wizard'">
                    <div class="col-md-12 padding-t_8">
                        <div class="theme-primary partition-full">
                            <span class="p-name text-white">{{ $t('ProjectRequest') }}</span>
                            <span class="float-right">
                                <a href="javascript:;" class="p-action-btn text-white" :title="$t('BacktoList')"
                                    @click="Close">
                                    <em class="fa fa-angle-double-left" aria-hidden="true"></em>
                                    <br />{{ $t('BacktoList') }}
                                </a>
                            </span>
                        </div>
                    </div>
                </div>
                <div class="border p-3">
                    <dynamic-form ref="requestform" lang="en" :mandatorytext="$t('MandatoryString')" :buttons="buttons"
                        :schema="FormSchema" v-on:OnSubmit="OnSubmit">
                    </dynamic-form>
                </div>
            </div>
        </section>
    </div>
</template>

<script>
import DataService from '../../../services/DataService';
export default {
    data() {
        return {
            isLoading: false,
            FormSchema: [
                {
                    layoutType: "four",
                    Data: [
                        {
                            astype: "TextField",
                            label: this.$t('Title'),
                            name: "TITLE",
                            value: "",
                            placeholder: "Enter Title Name",
                            validationRules: { required: true },
                            disabled: false,
                        },
                        {
                            astype: "NumericField",
                            label: this.$t('Budget'),
                            name: "BUDGET",
                            value: "",
                            placeholder: "",
                            validationRules: { required: true },
                            disabled: false,
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Start Date'),
                            name: "startdate",
                            value: "",
                            placeholder: this.$t("Start Date"),
                            validationRules: { required: false },
                            config: { mode: "date", format: "M/D/YYYY", minDate: new Date(),onChange: this.checkEndMinDat }
                        },
                        {
                            astype: "DateField",
                            label: this.$t("Due Date"),
                            name: "duedate",
                            value: "",
                            placeholder: this.$t("Due Date"),
                            validationRules: { required: false },
                            config: { mode: "date", format: "M/D/YYYY",minDate: new Date(), }
                        },
                    ],
                },
                {
                    layoutType: "single",
                    group_name: 'Attachment',
                    Data: [
                        {
                            astype: "FileField",
                            label: this.$t('Attachment'),
                            name: "Attachment",
                            value: "",
                            placeholder: "Select",
                            FieldIndex: 0,
                            config: {
                                maxSize: 100,
                                accept: [
                                    { fileType: 'jpg', iconClass: 'fa-file-image-o' },
                                    { fileType: 'jpeg', iconClass: 'fa-file-image-o' },
                                    { fileType: 'png', iconClass: 'fa-file-image-o' },
                                    { fileType: 'pdf', iconClass: 'fa-file-archive-o' },
                                    { fileType: 'mp4', iconClass: 'fa-video-camera' },
                                    { fileType: 'doc', iconClass: 'fa-file-text-o' },
                                    { fileType: 'docx', iconClass: 'fa-file-text-o' },
                                    { fileType: 'xlsx', iconClass: 'fa-file-excel-o' },
                                    { fileType: 'txt', iconClass: 'fa-file-text-o' }
                                ],
                                showSelectedFiles: [],
                                onChange: this.GetBase64String,
                                onDeleteSelectedFiles: this.onDeleteSelectedFiles,
                                multiple: true
                            },
                            validationRules: { required: false }
                        }
                    ]
                },
                {
                    layoutType: "single",
                    group_name: 'Description',
                    Data: [
                        {
                            astype: "TextAreaField",
                            label: this.$t('Description'),
                            name: "Description",
                            value: "",
                            placeholder: "",
                            config: { rows: 7 },
                            validationRules: { required: true },
                            disabled: false,
                        }
                    ]
                }
            ],
            buttons: [
                { type: "submit", class: "btn btn-success", text: "<i class='fa fa-save pr-2'></i>Save", isVisible: true },
                { type: "button", class: "btn btn-danger", text: "<i class='fa fa-close pr-2'></i>Cancel", onClick: this.Close }
            ],
            fileMulitpleData: [],
            CurrencyCode: '',
            callFrom:'',
            RequestId:0,
        }
    },
    created() {
        debugger
        var ths=this;
        ths.CurrencyCode = ths.GetUserInfo.Currency;
        ths.FormSchema.forEach(group => {
            group.Data.forEach(field => {
                if (field.name === 'BUDGET') {
                    field.label = `Budget ${ths.CurrencyCode}`;
                }
            });
        });
        ths.RequestId=ths.$route.params.QuotationId;
        if(ths.RequestId>0){
            ths.EditRequest();
        }
    },
    methods: {
        checkEndMinDat()
        {
            debugger
            var vm=this;
              var selectedstartdate= vm.FormSchema[0].Data[2].value;
              vm.FormSchema[0].Data[3].config.minDate =selectedstartdate;
        },
        GetBase64String(evt) {
            const vm = this;
            Array.from(evt.target.files).forEach(file => {
                const reader = new FileReader();
                reader.onload = (e) => {
                    const base64StringEncoded = e.target.result.split(',')[1];
                    const extension = file.name.split('.').pop();
                    vm.fileMulitpleData.push({
                        ModuleName: 'PROJECT',
                        SubModuleCode: 'PROJECT_DEATIL',
                        fileName: file.name,
                        fileSize: file.size,
                        contentType: file.type,
                        attachement_mime: JSON.stringify({ ContentType: file.type, Size: file.size, Extension: extension }),
                        base64String: base64StringEncoded
                    });
                };
                reader.readAsDataURL(file);
            });
        },
        EditRequest(){
            var ths = this;
            var url = `id=${ths.RequestId}`;
            DataService.GetDetails(url).then((response) => {
                if (response.data.result.data.length > 0) {
                    ths.FormSchema[0].Data[0].value = response.data.result.data[0].PROJECTTITLE;
                    ths.FormSchema[0].Data[2].value = response.data.result.data[0].STARTDATE;
                    ths.FormSchema[0].Data[3].value = response.data.result.data[0].DUEDATE;
                    ths.FormSchema[0].Data[1].value = response.data.result.data[0].BUDGET.toFixed(2);
                    ths.FormSchema[2].Data[0].value = response.data.result.data[0].DESCRIPTION;
                    ths.StatusCode = response.data.result.data[0].STATUSCODE;
                }
            })
            
        },
        ViewFiles: function (id) {
            var ths = this;
            var url = `id=${id}`;
            DataService.ViewFiles(url).then((response) => {
                if (response.data.result.length > 0) {
                    const ViewFilesData = response.data.result;
                    ViewFilesData.forEach((element)=>{
                        var Obj={
                            attachmentName: element.ATTACHMENTNAME,
                            attachmentPath: element.ATTACHMENTPATH
                        }
                       ths.FormSchema[1].Data[0].config.showSelectedFiles.push(Obj);
                    });
                }
            })
        },
        onDeleteSelectedFiles() {
            this.fileMulitpleData = [];
            if (this.FormSchema[1]?.Data[0]?.config?.showSelectedFiles) {
                this.FormSchema[1].Data[0].config.showSelectedFiles = [];
            }
        },
        async OnSubmit() {
            const vm = this;
            const Title = vm.$refs.requestform.getPropertyValue("TITLE", "value");
            const Budget = vm.$refs.requestform.getPropertyValue("BUDGET", "value");
            const startdate = vm.$refs.requestform.getPropertyValue("startdate", "value");
            const duedate = vm.$refs.requestform.getPropertyValue("duedate", "value");
            const Description = vm.$refs.requestform.getPropertyValue("Description", "value");
            const obj = {
                ProjectRequestId:vm.RequestId !=''? vm.RequestId:0,
                ProjectTitle: Title,
                Budget: Budget,
                StartDate: startdate,
                DueDate: duedate,
                Description: Description,
                StatusId: 1001,
                attachmentData: vm.fileMulitpleData.length ? vm.fileMulitpleData : null
            };
            try {
                const response = await DataService.SaveAddProjectRequest(JSON.stringify(obj));
                if (response.data != '' && response.data != null) {
                  if(response.data.result.DATA[0].Status_Message=="INSERT")
                  {                    
                    vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('ProjectRequest')]), "success", true, vm.$t("Alert"));
                    vm.Close();
                  }
                 else if(response.data.result.DATA[0].Status_Message=="UPDATE")
                  {                    
                    vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('ProjectRequest')]), "success", true, vm.$t("Alert"));
                    vm.Close();
                  }
                   else if(response.data.result.DATA[0].Status_Message=="EXISTS")
                  {                    
                    vm.ShowAlert(vm.$t('AlreadyExists', [vm.$t('ProjectRequest')]), "failure", true, vm.$t("Alert"));
                  }
                  else
                  {
                     vm.ShowAlert(vm.$t('ErrorWhileProcessingRequest'), "failure", true, vm.$t('Alert'));
                  }
                }
            } catch (error) {
                console.error("Submission failed:", error);
            }
        },
        Close() {
            this.$router.push({ name: 'ProjectRequestList' });
        }
    }
}
</script>
